def escape(s): return (s or "").replace("'", "''")

lines = ["-- Moroccan Laws Seed — paste into Supabase SQL Editor",
         "-- Generated by generate_seed.py\n"]

for (title, desc, cat, pdf, law_num, year, tags) in LAWS:
    uid = str(uuid.uuid4())
    tags_pg = "ARRAY[" + ",".join(f"'{escape(t)}'" for t in tags) + "]"
    lines.append(
        f"INSERT INTO law_documents (id,title,description,category,pdf_url,law_number,year,tags) VALUES "
        f"('{uid}','{escape(title)}','{escape(desc)}','{escape(cat)}','{escape(pdf)}','{escape(law_num)}',{year},{tags_pg});"
    )

sql = "\n".join(lines)
with open("moroccan_laws.sql", "w", encoding="utf-8") as f:
    f.write(sql)

print(f"✓ Generated {len(LAWS)} laws → moroccan_laws.sql")
